sql:
SELECT volume, difficulty, cpc, competitive_density, num_results, intent, query_type, device_type, location
FROM search_queries
WHERE keyword = 'what is an air ball in basketball' AND search_engine = '1';

SELECT COUNT(query_id) 
FROM search_queries 
WHERE search_engine = 'Bing';

SELECT feature_name, feature_description
FROM serp_features
WHERE feature_position > 1;

SELECT search_engine, AVG(volume) AS average_volume
FROM search_queries
GROUP BY search_engine;

SELECT search_queries.keyword, query_categories.category_name
FROM search_queries
JOIN query_categories ON search_queries.query_id = query_categories.query_id;

SELECT volume AS average_monthly_volume
FROM search_queries
WHERE query_id = 0;

SELECT AVG(cpc) AS average_cpc
FROM search_queries
WHERE keyword LIKE '%basketball%';

SELECT keyword, volume
FROM search_queries
WHERE volume > (SELECT AVG(volume) FROM search_queries);

SELECT DISTINCT u.user_id, al.query_id
FROM users u
JOIN access_logs al ON u.user_id = al.user_id;

SELECT sq.query_id, sq.keyword, sf.feature_name
FROM search_queries sq
LEFT JOIN serp_features sf ON sq.query_id = sf.query_id;

