sql:
SELECT AVG(difficulty) AS AverageDifficulty
FROM search_queries
WHERE num_results > (SELECT AVG(num_results) FROM search_queries);

SELECT keyword, volume, search_engine, location
FROM search_queries
WHERE volume = (SELECT MAX(volume) FROM search_queries);
